mapper.select:
SELECT main.STATUS_CD , ccd.COM_CD_NM AS STATUS_NM , main.REGISTER_CNT FROM ( SELECT INVM_EXNT_PGSG_CD AS STATUS_CD , COUNT(0) AS REGISTER_CNT FROM ( SELECT INVM_EXNT_RQST_ID , INVM_EXNT_PGSG_CD , ROW_NUMBER() OVER(PARTITION BY INVM_EXNT_RQST_ID ORDER BY RGSN_TS DESC) AS RNK , RGSN_TS FROM TB_BOX_IVT_EXNT_PGSG_R WHERE INVM_EXNT_RQST_ID IN (
#{transferId}
) ) WHERE RNK = 1 GROUP BY INVM_EXNT_PGSG_CD ) main LEFT JOIN TB_BOX_IVT_COM_CD_D ccd ON main.STATUS_CD = ccd.COM_CD_ID ORDER BY main.STATUS_CD ASC

SELECT main.STATUS_CD , ccd.COM_CD_NM AS STATUS_NM , main.REGISTER_CNT FROM ( SELECT EXNT_RSLT_CD AS STATUS_CD , COUNT(0) AS REGISTER_CNT FROM TB_BOX_IVT_EXNT_RQST_M WHERE 1=1 AND EXNT_RSLT_CD IS NOT NULL AND INVM_EXNT_RQST_ID IN (
#{transferId}
) GROUP BY EXNT_RSLT_CD ) main LEFT JOIN TB_BOX_IVT_COM_CD_D ccd ON main.STATUS_CD = ccd.COM_CD_ID ORDER BY main.STATUS_CD ASC

